def process_medication_request(medication_requests: List[dict], allergies: List[dict]) -> bool:
    medications_rxnorm_codes = {normalize_medication(request['medicationCodeableConcept']['coding'][0]['display']).rxnorm_code for request in medication_requests}

    # Convert allergy data to the internal model
    patient_allergies = [Allergy(allergy['patient'], allergy['substance']['coding'][0]['code'], allergy['type']) for allergy in allergies]

    interactions = INTERACTION_RULES  # Assume interaction rules are loaded

    if not perform_medication_checks(patient_allergies, interactions, medications_rxnorm_codes):
        generate_alerts(medication_requests, patient_allergies, interactions)
        return False
    return True

def generate_alerts(medication_requests: List[dict], allergies: List[Allergy], interactions: List[Interaction]):
    for request in medication_requests:
        rxnorm_code = normalize_medication(request['medicationCodeableConcept']['coding'][0]['display']).rxnorm_code
        if check_allergy(allergies, rxnorm_code):
            alert_message = f"Patient has a severe allergy to {normalize_medication(rxnorm_code).name}."
            generate_alert(request['patient'], 'allergy_contraindication', alert_message)

        medications_rxnorm_codes = {rxnorm_code}
        if check_ddi(interactions, medications_rxnorm_codes):
            alert_message = f"Potential drug-drug interaction with {normalize_medication(rxnorm_code).name}."
            generate_alert(request['patient'], 'ddi_contraindication', alert_message)

def generate_alert(patient_id: int, alert_type: str, message: str) -> Alert:
    return Alert(patient_id=patient_id, alert_type=alert_type, message=message)
