import requests

class FhirDal:
    def __init__(self, base_url):
        self.base_url = base_url

    def get_patient(self, patient_id):
        url = f"{self.base_url}/Patient/{patient_id}"
        response = requests.get(url)

        if response.status_code == 200:
            return response.json()
        else:
            raise Exception(f"Failed to retrieve patient: {response.content}")

    def get_medication_requests(self, patient_id):
        url = f"{self.base_url}/MedicationRequest?patient={patient_id}&status=active"
        response = requests.get(url)

        if response.status_code == 200:
            return response.json()
        else:
            raise Exception(f"Failed to retrieve medication requests: {response.content}")

    def get_vital_signs(self, patient_id):
        url = f"{self.base_url}/Observation?patient={patient_id}&category=vital-signs"
        response = requests.get(url)

        if response.status_code == 200:
            return response.json()
        else:
            raise Exception(f"Failed to retrieve vital signs: {response.content}")
