from drug_normalization_service import DrugNormalizationService
from mapping_service import MappingService

class CdsEngine:
    def __init__(self, base_url):
        self.normalizer = DrugNormalizationService(base_url)
        self.mapper = MappingService()

    def normalize_and_evaluate_ddi(self, medications, access_token):
        normalized_medications = []

        for medication in medications['entry']:
            resource = medication['resource']

            # Normalize drug name
            if 'code' in resource and 'coding' in resource['code'] and len(resource['code']['coding']) > 0:
                coding_system = resource['code']['coding'][0]['system']
                coding_code = resource['code']['coding'][0]['code']

                if coding_system == "http://www.nlm.nih.gov/research/umls/rxnorm":
                    normalized_medications.append({
                        'name': resource['display'],
                        'rxnorm_code': coding_code
                    })
                else:
                    drug_name = resource['display']
                    rxnorm_code = self.mapper.map_drug_name_to_rxnorm(drug_name)

                    if rxnorm_code:
                        normalized_medications.append({
                            'name': drug_name,
                            'rxnorm_code': rxnorm_code
                        })

        # Evaluate DDI rules using normalized medications
        ddis = []
        for i in range(len(normalized_medications)):
            for j in range(i + 1, len(normalized_medications)):
                ddi_rule = evaluate_ddi_rule(normalized_medications[i]['rxnorm_code'], normalized_medications[j]['rxnorm_code'])

                if ddi_rule:
                    ddis.append(ddi_rule)

        return ddis
