from kafka import KafkaConsumer

class SepsisScoringService:
    def __init__(self, bootstrap_servers):
        self.consumer = KafkaConsumer('vital-signs', 'lab-results',
                                      bootstrap_servers=bootstrap_servers,
                                      auto_offset_reset='earliest')

    def process_event(self, event_type, event_data):
        if event_type == 'Observation':
            patient_id = event_data['patient']

            # Evaluate sepsis risk based on vital signs and lab results
            is_severe_vitals = self.evaluate_sepsis_risk(event_data)

            if is_severe_vitals:
                self.generate_alert(patient_id, "sepsis", "CRITICAL")

