        if 'vital-signs' in observation['category']:
            heart_rate = next((item['valueQuantity']['value'] for item in observation['component']
                               if item['code']['coding'][0]['display'] == 'Heart Rate'), None)

            if heart_rate and heart_rate > 130:
                return True

        # Add more conditions as needed (e.g., lab results, other vital signs)

        return False

    def generate_alert(self, patient_id, alert_type, severity_level):
        print(f"Patient ID: {patient_id}")
        print(f"Alert Type: {alert_type}")
        print(f"Severity Level: {severity_level}")

if __name__ == '__main__':
