                allergy_code = observation['resource']['code']['coding'][0]['code']

                if evaluate_allergy_rule(drug_code, allergy_code):
                    allergic_reactions.append({
                        'drug': drug_code,
                        'allergen': allergy_code,
                        'severity': 'CRITICAL',
                        'description': f'Allergic reaction to {statement["resource"]["display"]}'
                    })

    return allergic_reactions
```

